request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?source ?target ?sourceName ?targetName WHERE {
  ?task bbo:name "Absage senden" .
  ?task tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "fbb0adafe6924f58ac902063a36646fe" .

  # Incoming flows
  OPTIONAL {
    ?inFlow a bbo:SequenceFlow ;
            bbo:has_targetRef ?task ;
            bbo:has_sourceRef ?source .
    OPTIONAL { ?source bbo:name ?sourceName . }
  }

  # Outgoing flows
  OPTIONAL {
    ?outFlow a bbo:SequenceFlow ;
             bbo:has_sourceRef ?task ;
             bbo:has_targetRef ?target .
    OPTIONAL { ?target bbo:name ?targetName . }
  }
}
LIMIT 25
